const listMemoryUsage = `-- name: ListMemoryUsage :many
SELECT id, workspace_id, memory_id, used_by_type, used_by_id, issue_id, task_queue_id, chat_session_id, action, outcome, created_at
FROM memory_usage
WHERE memory_id = $1
ORDER BY created_at DESC
LIMIT $2
`

type ListMemoryUsageParams struct {
	MemoryID pgtype.UUID `json:"memory_id"`
	Limit    int32       `json:"limit"`
}

func (q *Queries) ListMemoryUsage(ctx context.Context, arg ListMemoryUsageParams) ([]MemoryUsage, error) {
	rows, err := q.db.Query(ctx, listMemoryUsage, arg.MemoryID, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []MemoryUsage{}
	for rows.Next() {
		var i MemoryUsage
		if err := rows.Scan(
			&i.ID,
			&i.WorkspaceID,
			&i.MemoryID,
			&i.UsedByType,
			&i.UsedByID,
			&i.IssueID,
			&i.TaskQueueID,
			&i.ChatSessionID,
			&i.Action,
			&i.Outcome,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

